const StaticRoomDef *static_room_bank_get(u8 room_idx)
{
    if (room_idx >= STATIC_ROOM_BANK_COUNT) { return 0; }
    return &s_room_defs[room_idx];
}

u8 static_room_bank_count_for_mask(u8 exits_mask)
{
    if (exits_mask >= 16u) { return 0u; }
    return s_room_counts_by_mask[exits_mask];
}

u8 static_room_bank_index_for_mask(u8 exits_mask, u8 variant_idx)
{
    if (exits_mask >= 16u) { return STATIC_ROOM_BANK_INVALID_INDEX; }
    if (variant_idx >= s_room_counts_by_mask[exits_mask]) { return STATIC_ROOM_BANK_INVALID_INDEX; }
    return s_room_indices_by_mask[exits_mask][variant_idx];
}
